 1	import type { FC } from 'react';
 2	import { DisplayTitle } from 'src/components/DetailItems/DetailItem';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import { ForkliftControllerModel, type K8sResourceCommon } from '@kubev2v/types';
 6	import { Text } from '@patternfly/react-core';
 7	import { MTV_SETTINGS } from '@utils/links';
 8	
 9	import { EditField } from '../cards/EditField';
10	import type { InputComponentType } from '../cards/EditFieldTypes';
11	
12	import type { EditSettingsProps } from './EditSettingsProps';
13	import { controllerMemoryLimitOptions } from './options';
14	import SettingsSelectInput from './SettingsSelectInput';
15	
16	/**
17	 * ControllerMemoryLimitSelect component.
18	 * Wraps the SettingsSelectInput component with pre-defined options.
19	 */
20	const ControllerMemoryLimitSelect: InputComponentType = (props) => {
21	  return <SettingsSelectInput {...props} options={controllerMemoryLimitOptions} />;
22	};
23	
24	const EditControllerMemoryLimit: FC<EditSettingsProps> = (props) => {
25	  const { t } = useForkliftTranslation();
26	
27	  return (
28	    <EditField
29	      {...props}
30	      resource={props.resource as K8sResourceCommon}
31	      jsonPath={'spec.controller_container_limits_memory'}
32	      label={
33	        <DisplayTitle
34	          title={t('Controller main container memory limit')}
35	          showHelpIconNextToTitle
36	          moreInfoLink={MTV_SETTINGS}
37	          helpContent={
38	            <Text>
39	              {t(
40	                'Sets the memory limits allocated to the main container in the controller pod. The default value is 800Mi.',
41	              )}
42	            </Text>
43	          }
44	          crumbs={['spec', 'controller_container_limits_memory']}
45	        />
46	      }
47	      model={ForkliftControllerModel}
48	      helperText={t(
49	        'Enter the limit for memory usage by the controller in Mi. If empty, the default value will be used.',
50	      )}
51	      InputComponent={ControllerMemoryLimitSelect}
52	      defaultValue="800Mi"
53	    />
54	  );
55	};
56	
57	export default EditControllerMemoryLimit;

